  const gpuCards = MOCK_GPU_CARDS[node.id] ?? [];
  res.json({ data: { ...node, gpu_cards: gpuCards } });
});

app.get('/v1/admin/clusters/:clusterId/nodes/:nodeId', (req, res) => {
