  description: string;
  capabilities: {
    context_window: number;    // e.g. 131072
    max_output_tokens: number; // e.g. 4096
    json_mode: boolean;
    tool_calling: boolean;
    multi_modal: boolean;      // 是否支持图片/音频输入
    fine_tuning: boolean;      // Phase 2
